sql:
SELECT c.country_name, c.iso_3166, mno.operator_name
FROM countries c
INNER JOIN mobile_network_operators mno ON c.country_id = mno.country_id;

SELECT country_name 
FROM countries 
WHERE country_id NOT IN (
  SELECT country_id 
  FROM mobile_country_codes
);

SELECT mno.operator_name, c.country_name
FROM mobile_network_operators mno
JOIN countries c ON mno.country_id = c.country_id;

SELECT mobile_country_codes.mcc, countries.country_name, mobile_country_codes.coverage_area 
FROM mobile_country_codes 
JOIN countries ON mobile_country_codes.country_id = countries.country_id;

SELECT c.country_name, cnc.network_code_type
FROM countries c
JOIN country_network_codes cnc ON c.country_id = cnc.country_id;

SELECT COUNT(*)
FROM network_codes
WHERE network_code_type = 'GSM';
